query.sparql:
SELECT ?person ?personLabel WHERE {
  wd:Q1730 wdt:P138 ?person.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?animal ?animalLabel WHERE {
  ?operation wdt:P7779 ?militaryUnit.
  ?militaryUnit wdt:P798 wd:Q328.
  ?animal wdt:P410 ?operation.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?founder ?founderLabel WHERE {
  ?company wdt:P31 wd:Q830655;
           wdt:P10786 ?incorporationDate;
           wdt:P199 ?division.
  ?founder wdt:P102 wd:Q82955;
           wdt:P199 ?company.
  ?founder wdt:P39 wd:Q13218629.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work ?workLabel WHERE {
  ?author wdt:P50 wd:Q10000.
  ?work wdt:P50 ?author;
        wdt:P1433 wd:Q123456.
  ?work rdfs:label ?workLabel.
  FILTER(CONTAINS(LCASE(?workLabel), "middle school student"))
}

SELECT ?work ?workLabel WHERE {
  ?work wdt:P50 wd:Q29565.
  FILTER NOT EXISTS { ?work wdt:P6333 wd:Q12345678. } # Replace Q12345678 with the actual QID for the Witcher series
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?state WHERE {
  {
    wd:Q123456 wdt:P276 ?state.
    wd:Q789012 wdt:P276 ?state.
  }
}
